VALUES
  ('elementary-7fec267e-moex-00314', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '人民提起下列何種類型之行政訴訟，應先踐行訴願程序？', '["確認訴訟及一般給付訴訟", "課予義務訴訟及確認訴訟", "撤銷訴訟及課予義務訴訟", "課予義務訴訟及一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00315', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於簡易訴訟上訴程序之敘述，何者正確？', '["對於簡易程序之第一審判決，得上訴於管轄之地方法院，其審判以獨任行之", "對於簡易訴訟程序之第二審判決，當事人得逕向最高法院提起上訴，無上訴利益額數之限制", "對於簡易訴訟程序之第二審判決，提起第三審上訴，不須經原裁判法院之許可", "簡易訴訟程序第三審之性質，為法律審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00316', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於民事訴訟當事人能力之敘述，何者正確？', '["關於遺產分割訴訟，得列同為繼承人之胎兒為被告，除非將來胎兒係死產，否則胎兒具當事人能力", "公寓大廈管理委員會無當事人能力，不得作為訴訟上之原告", "獨資商號具有當事人能力，得作為民事訴訟之當事人", "若原告於訴訟進行中死亡，法院應逕以原告無當事人能力，裁定駁回原告之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00317', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於民事程序上公開審理原則之適用，下列敘述，何者錯誤？', '["民事督促程序，原則上不適用公開審理原則", "關於非訟事件之關係人、證人、鑑定人之訊問，並非以公開審理為原則", "於普通訴訟程序，法院為審理時，得經兩造合意，而不進行公開審理", "遺產分割請求事件之審理，均應適用公開審理原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00318', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '甲家住臺東，於連假期間騎機車至屏東遊玩，行經墾丁時，汽車臨停於路旁之駕駛乙（家住臺中）突開車 門，甲閃避不及，因此而身受重傷。甲若欲起訴向乙請求民事損害賠償，其得向何法院提起訴訟？', '["僅得向臺灣臺東地方法院起訴", "僅得向臺灣屏東地方法院起訴", "得向臺灣臺中地方法院或臺灣屏東地方法院起訴", "得向臺灣臺東地方法院或臺灣屏東地方法院起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00319', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '甲向乙借款新臺幣（下同）100萬元，由丙為保證人，其後因甲投資失利，無法清償借款。下列關於該保 證契約之敘述，何者正確？', '["保證債務之範圍，以主債務100萬元為限，故丙無須對主債務之利息或甲未如期還款所致之違約金，負 保證之責", "由於丙向乙為清償後，得向甲求償，故即使乙未就甲之財產強制執行而直接向丙請求清償，丙不得拒絕", "乙得對於甲或丙，同時或先後請求全部或一部之給付", "丙得以甲對於乙之債權，主張抵銷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00320', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '甲與乙訂立買賣契約，係向乙購買A屋，雙方約定買賣價金新臺幣（下同）1,000萬元。乙將A屋交付於 甲使用後，尚未辦理所有權移轉登記，A屋即因地震而滅失。下列敘述，何者正確？', '["甲已取得A屋之占有，應給付乙1,000萬元", "甲尚未取得A屋之所有權，故無須給付乙買賣價金", "甲乙雙方應互相讓步，由甲給付乙500萬元", "由法院斟酌甲乙雙方之經濟狀況，決定甲給付金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00321', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '依民法第943條第1項規定，占有人於占有物上行使之權利，推定其適法有此權利。下列何者為此項推 定範圍之列？', '["承租人占有其所承租轎車之權利", "普通地上權人占有地上權標的物之權利", "受寄人保管寄託之鑽石", "所有人占有其所有之腳踏車"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00322', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於普通抵押權之敘述，何者錯誤？', '["抵押權為不移轉占有而供債權擔保之不動產物權，且抵押人得為債務人以外之第三人", "抵押權之效力及於抵押物滅失後之殘餘物，以及非依物之通常用法而分離成為獨立之動產者", "不動產所有人設定地上權後，於同一不動產上仍得設定抵押權，但其抵押權不因此而受影響", "抵押權人於債權清償期屆滿後，為受清償，得訂立契約，取得抵押物之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00323', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者正確？', '["最高限額抵押權所擔保之債權，於原債權確定前讓與他人者，其最高限額抵押權應隨同移轉", "抵押權人死亡時，最高限額抵押權則當然消滅", "最高限額抵押權所擔保之原債權確定後，其擔保效力原則上不及於其後繼續發生之債權", "最高限額抵押權所擔保之債權，其請求權已因時效而消滅，如抵押權人於消滅時效完成後，五年間不實 行其抵押權者，其抵押權消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
